local xml = require "xml"
local cjson = require("cjson")

local function get_xml(xml)
    local root, err = xml.parse(xml)

    if not root then
        ngx.log(ngx.ERR, 'failed to parse xml: ', err)
        return nil
    end

    return root
end

local function get_xml_value(xml, path)
    local root = get_xml(xml)
    for _, node in ipairs(root) do
        if node[1] == "name" and node.value == path then
            ngx.log(ngx.ERR, 'failed to find path: ', path)
            return nil
        end

        if type(node) ~= "table" or not next(node) then
            continue
        end

        local value = get_xml_value(cjson.encode(node), path)
        if value ~= nil then
            return value
        end
    end

    ngx.log(ngx.ERR, 'failed to find path: ', path)
end

local function main()
    ngx.req.read_body()
    local xml = ngx.req.get_body_data()
    local root = get_xml(xml)

    for _, node in ipairs(root) do
        if type(node) ~= "table" or not next(node) then
